What does this program print?

```cpp
#include <sstream>
#include <iostream>
int main() {
    std::stringstream ss("ABCDE");
    ss.seekg(3, std::ios::beg);
    char c;
    ss.get(c);
    std::cout << c << "\n";
}
```

What does this program print?

```cpp
#include <sstream>
#include <iostream>
int main() {
    std::stringstream ss("hello world");
    std::string a, b;
    ss >> a;
    std::streampos p = ss.tellg();
    ss >> b;
    std::cout << b << "\n";
    ss.seekg(p);
    ss >> b;
    std::cout << b << "\n";
}
```

This program is supposed to read `"abc"` from the string stream twice, but the second read produces garbage. What is the bug?

```cpp
#include <sstream>
#include <iostream>
#include <string>
int main() {
    std::istringstream iss("abc");
    std::string s;
    iss >> s;
    std::cout << s << "\n";
    iss.seekg(0);   // try to reset
    iss >> s;
    std::cout << s << "\n";
}
```
